import React, { useEffect, useRef, useState } from 'react';
// import axios from 'axios';

// CONFIGURACIÓN DEL COMPONENTE
const anchoRelativo = 1.5;     // Proporción ancho = altura * anchoRelativo
const espaciadoX = 16;         // Espacio horizontal entre imágenes en píxeles
const espaciadoY = 10;         // Espacio vertical entre filas (interno)

const shuffleArray = (array) => {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
};

const CarruselImagenes = ({ altura, filas, backendUrl, modoPrueba = true }) => {
  const [imagenes, setImagenes] = useState([]);
  const [imagenesDistribuidas, setImagenesDistribuidas] = useState([]);
  const contenedorRef = useRef(null);

  const distribuirEquitativamente = (imagenes, filas) => {
    const distribuidas = Array.from({ length: filas }, () => []);
    imagenes.forEach((img, index) => {
      distribuidas[index % filas].push(img);
    });
    return distribuidas;
  };

  const obtenerImagenesPrueba = () => {
    const cantidad = 8;
    const rutas = Array.from({ length: cantidad }, (_, i) =>
      `/media/homePage/carruselImagenes/img${i + 1}.jpg`
    );

    const imagenesBarajadas = shuffleArray(rutas);
    setImagenes(imagenesBarajadas);
    setImagenesDistribuidas(distribuirEquitativamente(imagenesBarajadas, filas));
  };

  useEffect(() => {
    if (modoPrueba) {
      obtenerImagenesPrueba();
    } else {
      // axios.get...
    }
  }, [backendUrl, modoPrueba]);

  useEffect(() => {
    const intervalo = setInterval(() => {
      const siguiente = shuffleArray(imagenes);
      setImagenesDistribuidas(distribuirEquitativamente(siguiente, filas));
    }, 10000);
    return () => clearInterval(intervalo);
  }, [imagenes, filas]);

  return (
    <div
      ref={contenedorRef}
      className="w-full overflow-hidden relative"
      style={{ height: `${altura}px` }}
    >
      {imagenesDistribuidas.map((fila, i) => {
        const filaAltura = altura / filas - espaciadoY;
        const imgAlto = filaAltura;
        const imgAncho = filaAltura * anchoRelativo;

        return (
          <div
            key={i}
            className="flex absolute"
            style={{
              top: `${(100 / filas) * i}%`,
              height: `${filaAltura}px`,
              animation: `${i % 2 === 0 ? 'moverIzquierda' : 'moverDerecha'} 30s linear infinite`,
              gap: `${espaciadoX}px`,
              paddingTop: `${espaciadoY / 2}px`,
              paddingBottom: `${espaciadoY / 2}px`
            }}
          >
            {fila.map((img, idx) => (
              <img
                key={idx}
                src={img}
                alt={`img-${idx}`}
                style={{
                  height: `${imgAlto}px`,
                  width: `${imgAncho}px`,
                  objectFit: 'cover',
                  flexShrink: 0,
                }}
              />
            ))}
          </div>
        );
      })}

      <style>{`
        @keyframes moverIzquierda {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
        @keyframes moverDerecha {
          0% { transform: translateX(-50%); }
          100% { transform: translateX(0); }
        }
      `}</style>
    </div>
  );
};

export default CarruselImagenes;
